set CONTENT=@rem Copyright 2015 the original author or authors. @rem Licensed under the Apache License, Version 2.0 (the "License"); @rem you may not use this file except in compliance with the License. @rem You may obtain a copy of the License at @rem https://www.apache.org/licenses/LICENSE-2.0 @rem Unless required by applicable law or agreed to in writing, software @rem distributed under the License is distributed on an "AS IS" BASIS, @rem WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied. @rem See the License for the specific language governing permissions and @rem limitations under the License. @rem SPDX-License-Identifier: Apache-2.0 @rem @if "%DEBUG%"=="" @echo off
set "CONTENT=%CONTENT% @rem ########################################################################## @rem Gradle startup script for Windows @rem ########################################################################## @rem Set local scope for the variables setlocal EnableExtensions set DIRNAME=%~dp0
set "CONTENT=%CONTENT% if "%DIRNAME%"=="" set DIRNAME=. set APP_BASE_NAME=%~n0 set APP_HOME=%DIRNAME% @rem Add default JVM options set DEFAULT_JVM_OPTS=-Dfile.encoding=UTF-8 "-Xmx64m" "-Xms64m" @rem Find java.exe if defined JAVA_HOME goto findJavaFromJavaHome set JAVA_EXE=java.exe %JAVA_EXE% -version >NUL 2>&1
set "CONTENT=%CONTENT% if %ERRORLEVEL% equ 0 goto execute echo ERROR: JAVA_HOME is not set "%COMSPEC%" /c exit 1 :findJavaFromJavaHome set JAVA_HOME=%JAVA_HOME:"=% set JAVA_EXE=%JAVA_HOME%/bin/java.exe if exist "%JAVA_EXE%" goto execute echo ERROR: JAVA_HOME is set to an invalid directory "%COMSPEC%" /c exit 1 :execute endlocal & "%JAVA_EXE%" %DEFAULT_JVM_OPTS% %JAVA_OPTS% %GRADLE_OPTS% "-Dorg.gradle.appname=%APP_BASE_NAME%" -jar "%APP_HOME%\gradle\wrapper\gradle-wrapper.jar" %* & call :exitWithErrorLevel :exitWithErrorLevel "%COMSPEC%" /c exit %ERRORLEVEL%